<?php\n\nnamespace App\Models;\n\nuse Illuminate\Database\Eloquent\Model;\nuse Illuminate\Database\Eloquent\Relations\HasMany;\n\nclass User extends Model\n{\n    protected $fillable = [ 'name', 'email', 'password' ];\n    \n    // Relationships\n    public function profile() : HasMany {\n        return $this->hasOne(Profile::class);\n    }\n    \n    public function subscriptions() : HasMany {\n        return $this->hasMany(Subscription::class);\n    }\n    \n    public function payments() : HasMany {\n        return $this->hasMany(Payment::class);\n    }\n    \n    public function messages() : HasMany {\n        return $this->hasMany(Message::class);\n    }\n    \n    public function matches() : HasMany {\n        return $this->hasMany(Match::class);\n    }\n    \n    // Methods\n    public function getSubscriptionTier() : string {\n        // Logic to determine subscription tier\n        return 'free'; // or return the actual tier\n    }\n    \n    public function isGracePeriod() : bool {\n        // Logic to determine if in grace period\n        return false; // or implement the real check\n    }\n    \n    public function trackActivity() : void {\n        // Logic to track user activity\n    }\n}